pub fn timer_interval() -> usize {
    timer_freq() / TIMER_TICKS_PER_SEC
}

fn timer_freq() -> usize {
    let base = cpucfg(0x4);
    let cfg5 = cpucfg(0x5);
    let numerator = cfg5 & 0xffff;
    let denominator = (cfg5 >> 16) & 0xffff;

    if denominator == 0 {
        return 100_000_000;
    }

    base.saturating_mul(numerator) / denominator
}

fn cpucfg(index: usize) -> usize {
    let value: usize;
    unsafe {
        core::arch::asm!(
            "cpucfg {value}, {index}",
            value = out(reg) value,
            index = in(reg) index,
            options(nostack)
        );
    }
    value
}

