    crate::println!("[la-ctx] bounce entered, switching back");
    unsafe {
        switch_task_context(
            core::ptr::addr_of_mut!(CTX_BOUNCE_STACK) as *mut TaskContext,
            CTX_SAVE_PTR,
        );
    }
}

pub fn loongarch64_ctx_smoke() {
    crate::println!("[la-ctx] testing switch_task_context");
    let stack_top = unsafe { core::ptr::addr_of!(CTX_BOUNCE_STACK) as usize + 4096 };
    let bounce_ctx = TaskContext::new_kernel_context(ctx_bounce_entry as usize, stack_top);
    let mut save_ctx = TaskContext::zero_init();

    unsafe {
        CTX_SAVE_PTR = core::ptr::addr_of!(save_ctx);
        switch_task_context(
            core::ptr::addr_of_mut!(save_ctx),
            &bounce_ctx as *const TaskContext,
        );
    }

    crate::println!("[la-ctx] switch_task_context round-trip passed");
}

