pub fn syscall(id: usize, args: [usize; 6]) -> isize {
    match id {
        SYS_WRITE => fd::sys_write(args[0], args[1], args[2]),
        SYS_READ => fd::sys_read(args[0], args[1], args[2]),
        SYS_LSEEK => fd::sys_lseek(args[0], args[1] as isize, args[2]),
        SYS_STATFS | SYS_FSTATFS => fd::sys_statfs(args[1]), // args[1] = buf ptr
        SYS_TRUNCATE | SYS_FTRUNCATE => fd::sys_ftruncate(args[0], args[1]),
        SYS_PREAD => fd::sys_pread(args[0], args[1], args[2], args[3]),
        SYS_PWRITE => fd::sys_pwrite(args[0], args[1], args[2], args[3]),
        SYS_UTIMENSAT => 0,
        SYS_GETDENTS64 => fd::sys_getdents64(args[0], args[1], args[2]),
        SYS_CLOSE => fd::sys_close(args[0]),
        SYS_OPENAT => fd::sys_openat(args[0] as isize, args[1], args[2], args[3]),
        SYS_GETCWD => fd::sys_getcwd(args[0], args[1]),
        SYS_DUP => fd::sys_dup(args[0]),
        SYS_DUP3 => fd::sys_dup3(args[0], args[1], args[2]),
        SYS_MKDIRAT => fd::sys_mkdirat(args[0] as isize, args[1], args[2]),
        SYS_UNLINKAT => fd::sys_unlinkat(args[0] as isize, args[1], args[2]),
        SYS_UMOUNT2 => fd::sys_umount2(args[0], args[1]),
        SYS_MOUNT => fd::sys_mount(args[0], args[1], args[2], args[3], args[4]),
        SYS_CHDIR => fd::sys_chdir(args[0]),
        SYS_PIPE2 => fd::sys_pipe2(args[0], args[1]),
        SYS_FSTAT => fd::sys_fstat(args[0], args[1]),
        SYS_FSTATAT => fd::sys_fstatat(args[0] as isize, args[1], args[2], args[3]),
        SYS_MMAP => fd::sys_mmap(args[0], args[1], args[2], args[3], args[4], args[5]),
        SYS_MUNMAP => fd::sys_munmap(args[0], args[1]),
        SYS_TEST => {
            crate::kprintln!("[syscall] sys_test");
            1234
        }
        SYS_BRK => mm::sys_brk(args[0]),
        SYS_EXIT | SYS_EXIT_GROUP => task::sys_exit(args[0]),
        SYS_YIELD => task::sys_yield(),
        SYS_NANOSLEEP => time::sys_nanosleep(args[0], args[1]),
        SYS_TIMES => time::sys_times(args[0]),
        SYS_UNAME => time::sys_uname(args[0]),
        SYS_GETPID => task::sys_getpid(),
        SYS_GETPPID => task::sys_getppid(),
        SYS_GETTIMEOFDAY => time::sys_gettimeofday(args[0], args[1]),
        SYS_WAITPID => task::sys_waitpid(args[0] as isize, args[1], args[2]),
        SYS_FORK => task::sys_fork(),
        SYS_CLONE | SYS_CLONE3 => task::sys_clone(args[0], args[1], args[2], args[3], args[4]),
        SYS_FCNTL => 0,
        SYS_SIGACTION | SYS_SIGPROCMASK | SYS_SIGRETURN | SYS_RT_SIGSUSPEND => 0,
        SYS_KILL => crate::task::send_signal_to_pid(args[0], args[1]),
        SYS_TKILL => crate::task::send_signal_to_pid(args[0], args[1]), // tkill(tid, sig)
        SYS_EXECVE => task::sys_execve(args[0], args[1], args[2]),
        SYS_STATX => fd::sys_statx(args[0], args[1], args[2], args[3], args[4]),
        SYS_LINKAT | SYS_SYMLINKAT => 0, // accept symlink creation for busybox --install
        SYS_READLINKAT => 0, // pretend success for /proc/self/exe etc.
        SYS_IOCTL => crate::syscall::errno::err(crate::syscall::errno::ENOTTY),
        SYS_FACCESSAT => 0, // ld.so uses this to check if libs exist; always succeed
        SYS_MPROTECT => fd::sys_mprotect(args[0], args[1], args[2]),
        SYS_PRLIMIT64 => fd::sys_prlimit64(args[0], args[1], args[2], args[3]),
        SYS_READLINKAT => fd::sys_readlinkat(args[0] as isize, args[1], args[2], args[3]),
        SYS_GETRANDOM => fd::sys_getrandom(args[0], args[1], args[2]),
        SYS_CLOCK_GETTIME => time::sys_clock_gettime(args[0], args[1]),
        SYS_GETUID | SYS_GETEUID | SYS_GETGID | SYS_GETEGID => 0,
        SYS_SET_TID_ADDRESS => {
            crate::task::current().set_clear_child_tid(args[0]);
            crate::task::current().pid() as isize
        }
        SYS_SET_ROBUST_LIST => {
            crate::task::current().set_robust_list(args[0]);
            0
        }
        SYS_BRK_SIMPLE => {
            if args[0] != 0 { crate::task::with_current_memory_set(|s| s.brk(args[0]) as isize) }
            else { 0 }
        }
        SYS_WRITEV => fd::sys_writev(args[0], args[1], args[2]),
        SYS_FUTEX => fd::sys_futex(args[0], args[1], args[2]),
        SYS_SHUTDOWN => {
            crate::kprintln!("[syscall] shutdown requested");
            crate::arch::shutdown();
        }
        _ => {
            crate::kprintln!("[syscall] unsupported syscall id={}", id);
            crate::syscall::errno::err(crate::syscall::errno::ENOSYS)
        }
    }
}

