}

impl TaskControlBlock {
    pub fn new_initproc(pid: usize) -> Self {
        Self::new_user_app(pid, "initproc", None)
    }

    pub fn new_user_app(pid: usize, app_name: &str, parent: Option<usize>) -> Self {
        let (memory_set, entry, user_stack_top, _tls) =
            loader::load_user_app(app_name).expect("[task] user app not found");

        let kernel_stack_id = kernel_stack::alloc_kernel_stack();
        let trap_cx_ptr = kernel_stack::trap_cx_ptr(kernel_stack_id);

        unsafe {
            trap_cx_ptr.write(TrapContext::app_init_context(entry, user_stack_top, 0));
        }

        crate::kprintln!(
            "[task] user app: name={}, pid={}, parent={:?}, entry={:#x}, user_stack_top={:#x}, token={:#x}, kstack_id={}, kstack_top={:#x}, trap_cx={:#x}",
            app_name,
            pid,
            parent,
            entry,
            user_stack_top,
            memory_set.token(),
            kernel_stack_id,
            kernel_stack::kernel_stack_top(kernel_stack_id),
            trap_cx_ptr as usize,
        );

        Self {
            pid,
            status: TaskStatus::Ready,
            kind: TaskKind::UserProcess,
            memory_set: Some(memory_set),
            kernel_stack_id,
            task_cx: crate::arch::TaskContext::zero_init(),
            exit_code: 0,
            block_target: BlockTarget::None,
            parent,
            children: Vec::new(),
            files: Vec::new(),
            cwd: String::from("/"),
            clear_child_tid: None,
            robust_list: None,
            saved_trap_cx: None,
            pending_signals: 0,
        }
    }

    pub fn new_forked_user_process(
        pid: usize,
        parent_pid: usize,
        memory_set: MemorySet,
        trap_cx: TrapContext,
        cwd: String,
        files: Vec<Option<UserFile>>,
    ) -> Self {
        let kernel_stack_id = kernel_stack::alloc_kernel_stack();
        let trap_cx_ptr = kernel_stack::trap_cx_ptr(kernel_stack_id);

        unsafe {
            trap_cx_ptr.write(trap_cx);
        }

        crate::kprintln!(
            "[task] fork child: pid={}, parent={}, token={:#x}, kstack_id={}, kstack_top={:#x}, trap_cx={:#x}",
            pid,
            parent_pid,
            memory_set.token(),
            kernel_stack_id,
            kernel_stack::kernel_stack_top(kernel_stack_id),
            trap_cx_ptr as usize,
        );

        Self {
            pid,
            status: TaskStatus::Ready,
            kind: TaskKind::UserProcess,
            memory_set: Some(memory_set),
            kernel_stack_id,
            task_cx: crate::arch::TaskContext::zero_init(),
            exit_code: 0,
            block_target: BlockTarget::None,
            parent: Some(parent_pid),
            children: Vec::new(),
            files,
            cwd,
            clear_child_tid: None,
            robust_list: None,
            saved_trap_cx: None,
            pending_signals: 0,
        }
    }

    pub fn exec_user_app(&mut self, app_name: &str, argv: &[&[u8]]) -> isize {
        if self.kind != TaskKind::UserProcess {
            crate::println!(
                "[exec] exec from non-user task: pid={}, kind={:?}",
                self.pid,
                self.kind,
            );
            return -1;
        }

        let Some(app) = crate::loader::find_user_app(app_name) else {
            crate::kprintln!(
                "[exec] builtin user app not found: pid={}, app={}",
                self.pid,
                app_name,
            );
            return -1;
        };

        crate::kprintln!(
            "[exec] builtin user app: pid={}, path={}, name={}, size={:#x}",
            self.pid,
            app_name,
            app.name,
            app.data.len(),
        );

        // Use caller-supplied argv if available, otherwise default to app_name
        if argv.is_empty() {
            let default_argv: [&[u8]; 1] = [app_name.as_bytes()];
            self.exec_elf_bytes(app_name, app.data, &default_argv)
        } else {
            self.exec_elf_bytes(app_name, app.data, argv)
        }
    }

