use super::context::TrapContext;

const USER_ENV_CALL: usize = 8;
const BREAKPOINT: usize = 3;
const INSTRUCTION_PAGE_FAULT: usize = 12;
const LOAD_PAGE_FAULT: usize = 13;
const STORE_PAGE_FAULT: usize = 15;

static mut TIMER_TICK: usize = 0;
const ENABLE_TIMER_PREEMPT: bool = false;

#[unsafe(no_mangle)]
#[cfg(feature = "arch_riscv64")]
pub extern "C" fn rust_trap_handler(cx: &mut TrapContext) {
    crate::kprintln!(
        "[trap] handler begin, from={}, scause={:#x}, sepc={:#x}, stval={:#x}",
        if cx.from_user() { "U" } else { "S" },
        cx.scause,
        cx.sepc,
        cx.stval
    );
    if cx.is_interrupt() {
        if crate::arch::is_timer_interrupt(cx.scause) {
            unsafe {
                TIMER_TICK += 1;

                if TIMER_TICK <= 10 {
                    crate::kprintln!(
                        "[trap] timer interrupt: tick={}, from={}, sepc={:#x}",
                        TIMER_TICK,
                        if cx.from_user() { "U" } else { "S" },
                        cx.sepc
                    );
                }
            }

            crate::arch::set_next_timer();

            let now = crate::arch::read_time();
            crate::task::wake_expired_sleepers(now);

            if ENABLE_TIMER_PREEMPT && cx.from_user() {
                crate::task::try_suspend_current_and_run_next();
            }

            return;
        }

        crate::println!("[trap] unhandled interrupt: scause={:#x}", cx.scause);
        loop {}
    }

    match cx.cause_code() {
        USER_ENV_CALL => {
            let syscall_id = cx.x[17]; // a7
            let args = [
                cx.x[10], // a0
                cx.x[11], // a1
                cx.x[12], // a2
                cx.x[13], // a3
                cx.x[14], // a4
                cx.x[15], // a5
            ];

            crate::kprintln!(
                "[trap] user syscall: id={}, args=[{:#x}, {:#x}, {:#x}]",
                syscall_id,
                args[0],
                args[1],
                args[2]
            );

            if syscall_id == crate::syscall::SYS_YIELD {
                // yield 可能不会返回当前 handler，所以必须先修正当前任务现场。
                cx.x[10] = 0;
                cx.sepc += 4;

                let ret = crate::syscall::syscall(syscall_id, args);

                // 如果没有其他 ready task，sys_yield 会返回，这时正常写回返回值。
                cx.x[10] = ret as usize;
                return;
            }

            let ret = crate::syscall::syscall(syscall_id, args);

            if syscall_id == crate::syscall::SYS_EXECVE && ret == 0 {
                crate::kprintln!(
                    "[trap] execve success: trap context replaced, skip normal syscall return"
                );
                return;
            }

            // syscall 返回值写回 a0
            cx.x[10] = ret as usize;
            cx.sepc += 4;
        }
        BREAKPOINT => {
            crate::kprintln!(
                "[trap] breakpoint from {}",
                if cx.from_user() { "U" } else { "S" }
            );
            // 当前 ebreak 是 .word 0x00100073，固定 4 字节
            cx.sepc += 4;
        }
        INSTRUCTION_PAGE_FAULT | LOAD_PAGE_FAULT | STORE_PAGE_FAULT => {
            crate::kprintln!(
                "[trap] user page fault: scause={:#x}, sepc={:#x}, stval={:#x}",
                cx.scause,
                cx.sepc,
                cx.stval
            );

            crate::task::with_current_memory_set(|space| {
                match space.find_area(crate::mm::address::VirtAddr(cx.stval)) {
                    Some(area) => {
                        let perm = area.perm();
                        crate::kprintln!(
                            "[trap] fault area: {:?}, perm=R{} W{} X{} U{}",
                            area.area_type(),
                            if perm.read { "+" } else { "-" },
                            if perm.write { "+" } else { "-" },
                            if perm.execute { "+" } else { "-" },
                            if perm.user { "+" } else { "-" },
                        );
                    }
                    None => {
                        crate::kprintln!("[trap] fault va not in any area");
                    }
                }
            });

            // Kill the faulting user process instead of panicking the kernel
            crate::kprintln!("[trap] user page fault at {:#x}, killing process", cx.sepc);
            crate::task::exit_current(-1);
        }
        _ => {
            crate::kprintln!("[trap] unhandled trap at sepc={:#x}, killing process", cx.sepc);
            crate::task::exit_current(-1);
        }
    }
}

