#[derive(Copy, Clone, Debug)]
pub enum ScheduleCause {
    Exit,
    Yield,
    Preempt,
    Block,
}

struct ScheduleEvent {
    cause: ScheduleCause,
    task: TaskControlBlock,
}

static mut SCHEDULE_EVENT_SLOT: Option<ScheduleEvent> = None;

// static mut EXITED_TASK_SLOT: Option<TaskControlBlock> = None;

pub struct Scheduler;

pub fn enter_from_exit(task: TaskControlBlock) -> ! {
    enter_with_event(ScheduleCause::Exit, task)
}

pub fn enter_from_yield(task: TaskControlBlock) -> ! {
    enter_with_event(ScheduleCause::Yield, task)
}

pub fn enter_from_preempt(task: TaskControlBlock) -> ! {
    enter_with_event(ScheduleCause::Preempt, task)
}

fn enter_with_event(cause: ScheduleCause, task: TaskControlBlock) -> ! {
    unsafe {
        let slot = core::ptr::addr_of_mut!(SCHEDULE_EVENT_SLOT);

        if (*slot).is_some() {
            panic!("[scheduler] schedule event slot occupied");
        }

        *slot = Some(ScheduleEvent { cause, task });
    }

    let stack_top = task::context::scheduler_stack_top();
    let entry = scheduler_entry as usize;

    crate::kprintln!(
        "[scheduler] switch to scheduler stack: cause={:?}, top={:#x}",
        cause,
        stack_top
    );

    crate::arch::switch_to_scheduler_stack(stack_top, entry)
}

pub fn enter_from_block(task: TaskControlBlock) -> ! {
    enter_with_event(ScheduleCause::Block, task)
}

