#[cfg(feature = "arch_loongarch64")]
const UART0: usize = 0x8000_0000_1fe0_01e0;

#[cfg(not(feature = "arch_loongarch64"))]
const UART0: usize = 0x1000_0000;

pub struct Serial;

impl Serial {
    pub fn putchar(c: u8) {
        unsafe {
            #[cfg(feature = "arch_loongarch64")]
            while core::ptr::read_volatile((UART0 + 5) as *const u8) & (1 << 5) == 0 {}

            core::ptr::write_volatile(UART0 as *mut u8, c);
        }
    }

    pub fn puts(s: &str) {
        for b in s.bytes() {
            if b == b'\n' {
                Self::putchar(b'\r');
            }
            Self::putchar(b);
        }
    }
}

impl Write for Serial {
    fn write_str(&mut self, s: &str) -> fmt::Result {
        Serial::puts(s);
        Ok(())
    }
}

pub fn _print(args: fmt::Arguments) {
    use core::fmt::Write;
    let _ = Serial.write_fmt(args);
}
